import React, { useState, useEffect } from 'react';
import Navbar from '../components/Navbar';
import TaskCard from '../components/TaskCard';
import AddTaskModal from '../components/AddTaskModal';
import { LayoutDashboard, Users, Clock, CheckCircle2, AlertCircle } from 'lucide-react';
import { fetchTasks } from '../api';

const Dashboard = () => {
  const [tasks, setTasks] = useState([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const userRole = localStorage.getItem('role') || 'member'; // admin or member

  useEffect(() => {
    const getTasks = async () => {
      try {
        const { data } = await fetchTasks();
        setTasks(data);
      } catch (err) { console.log(err); }
    };
    getTasks();
  }, []);

  // Stats logic
  const stats = [
    { label: 'Total Tasks', value: tasks.length, icon: <LayoutDashboard size={20}/>, color: 'text-blue-400' },
    { label: 'Completed', value: tasks.filter(t => t.status === 'Completed').length, icon: <CheckCircle2 size={20}/>, color: 'text-green-400' },
    { label: 'Overdue', value: 2, icon: <AlertCircle size={20}/>, color: 'text-red-400' },
    { label: 'Team Members', value: 5, icon: <Users size={20}/>, color: 'text-purple-400' },
  ];

  return (
    <div className="min-h-screen text-white bg-[#0f172a]">
      <Navbar />
      <AddTaskModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} />

      <main className="pt-28 pb-12 px-6 max-w-7xl mx-auto">
        {/* Stats Grid */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-10">
          {stats.map((s, i) => (
            <div key={i} className="p-4 bg-white/5 border border-white/10 rounded-2xl backdrop-blur-md">
              <div className={`${s.color} mb-2`}>{s.icon}</div>
              <div className="text-2xl font-bold">{s.value}</div>
              <div className="text-gray-400 text-xs uppercase tracking-wider">{s.label}</div>
            </div>
          ))}
        </div>

        <div className="flex justify-between items-end mb-8">
          <div>
            <h1 className="text-3xl font-bold">Project Overview</h1>
            <p className="text-gray-400">Tracking team progress and assignments.</p>
          </div>
          
          {/* Admin Only Button */}
          {userRole === 'admin' && (
            <button 
              onClick={() => setIsModalOpen(true)}
              className="bg-indigo-600 px-6 py-3 rounded-xl font-bold hover:scale-105 transition-all shadow-lg shadow-indigo-500/20"
            >
              + Create Task
            </button>
          )}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {tasks.map((task) => (
            <TaskCard key={task._id} task={task} />
          ))}
        </div>
      </main>
    </div>
  );
};

export default Dashboard;
